          <span>{isEditing ? 'JSON Edit' : 'JSON View'}</span>
          <span className="json-inspector__block-type">{block.type}</span>
        </div>
        <div className="json-inspector__actions">
          {!isEditing ? (
            <>
              <button
                className="icon-button"
